package com.pos;
import javax.swing.*;
public class UserFrame extends JFrame {private final UserSession s;public UserFrame(UserSession s){super(AppConstants.APP_NAME+" - Customer Portal");this.s=s;setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);setSize(1480,830);setLocationRelativeTo(null);JTabbedPane t=new JTabbedPane();t.addTab("Dashboard",new UserDashboardPanel(s));t.addTab("Products / Order",new ProductBrowserPanel(s));t.addTab("My Orders",new UserOrdersPanel(s));t.addTab("Order Items",new UserSimplePanel("My Order Items","SELECT o.order_no,p.product_name,i.quantity,i.unit_price,i.tax_amount,i.line_total FROM sales_order_items i JOIN sales_orders o ON o.order_id=i.order_id JOIN products p ON p.product_id=i.product_id JOIN customer_profiles cp ON cp.customer_id=o.customer_id WHERE cp.user_id=? ORDER BY i.order_item_id DESC",s.userId));t.addTab("Payments",new UserPaymentsPanel(s));t.addTab("Returns",new UserReturnPanel(s));t.addTab("Loyalty",new UserLoyaltyPanel(s));t.addTab("Announcements",new UserSimplePanel("Announcements","SELECT title,body,created_at FROM announcements WHERE status='ACTIVE' AND target_role IN ('ALL','CUSTOMER') ORDER BY created_at DESC"));t.addTab("Notifications",new UserSimplePanel("My Notifications","SELECT title,body,status,created_at FROM notifications WHERE user_id=? ORDER BY created_at DESC",s.userId));t.addTab("Messages",new UserMessagePanel(s));t.addTab("Feedback",new UserFeedbackPanel(s));t.addTab("Profile",new UserProfilePanel(s));add(t);JMenuBar mb=new JMenuBar();JMenu menu=new JMenu("Session");JMenuItem out=new JMenuItem("Logout");out.addActionListener(e->{Audit.log(s,"LOGOUT","Customer logged out");dispose();new AuthFrame().setVisible(true);});menu.add(out);mb.add(menu);setJMenuBar(mb);}}
